import { dom } from "niall-utils/ui";

import { decomposeSvg } from "./decomposeSvg.ts";
import { epicycleChain, toEpicycles } from "./epicycle.ts";
import { appMethods } from "./lib/index.ts";
import { safeAt } from "./safeAt.ts";

import type { Epicycle } from "./epicycle.ts";
import type { Config } from "./config.ts";
import type { StatefulAppContext } from "./lib/index.ts";

const SAMPLE_COUNT_PWR_2 = 7;
const SCALE = 1;
const PERIOD_SECONDS = 10;
const TRACE_STEPS = 200;

const animationFrame = (
  appCtx: StatefulAppContext<Config, Epicycle[]>
): void => {
  const { canvas, ctx, time, getState } = appCtx;
  ctx.fillStyle = "black";
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  const t = 1 - Math.abs((((time.now - time.start) / PERIOD_SECONDS) % 2) - 1);
  const epicycles = getState();
  const chain = epicycleChain(epicycles, t);

  ctx.strokeStyle = "#444";
  for (const [i, { amp }] of epicycles.entries()) {
    const centre = safeAt(chain, i);
    ctx.beginPath();
    ctx.arc(
      centre.x() * SCALE,
      centre.y() * SCALE,
      amp * SCALE,
      0,
      2 * Math.PI
    );
    ctx.stroke();
  }

  ctx.strokeStyle = "#888";
  ctx.beginPath();
  for (const [i, vec] of chain.entries()) {
    ctx[i === 0 ? "moveTo" : "lineTo"](vec.x() * SCALE, vec.y() * SCALE);
  }
  ctx.stroke();

  ctx.strokeStyle = "white";
  ctx.beginPath();
  for (let i = 0; i <= Math.floor(t * TRACE_STEPS); i++) {
    const tip = safeAt(epicycleChain(epicycles, i / TRACE_STEPS), -1);
    ctx[i === 0 ? "moveTo" : "lineTo"](tip.x() * SCALE, tip.y() * SCALE);
  }
  ctx.stroke();
};

